import { useNavigate, useLocation } from "react-router-dom";

function EgovError() {
  const navigate = useNavigate();
  const location = useLocation();

  let errormessage = location.state.msg || "알 수 없는 에러가 발생했습니다.";

  if (errormessage === "No message available") {
    errormessage = "알 수 없는 에러가 발생했습니다.";
  }

  const goBack = () => {
    navigate(-1, { replace: true }); // 이전 URL을 현재 페이지 인식하고 재 로딩하는 코드.
  };

  return (
    <div className="ERROR">
      <h1>Error</h1>
      <div className="box">
        <p>{errormessage}</p>
        <div className="btn_area">
          <button className="btn btn_blue_h46 w_130" onClick={goBack}>
            이전페이지
          </button>
        </div>
      </div>
    </div>
  );
}

export default EgovError;

